import type { APIRoute } from "astro";
import { getDb } from "../../../lib/db";
import { queueItem } from "../../../lib/db/schema";
import { eq, and, asc } from "drizzle-orm";
import { validateRunnerApiKey } from "../../../lib/runner-auth";

// GET /api/queue/next — pi-runner fetches next queued item
export const GET: APIRoute = async ({ request, url }) => {
  const apiKey = request.headers.get("x-runner-key") || url.searchParams.get("key");
  if (!validateRunnerApiKey(apiKey)) {
    return new Response(JSON.stringify({ error: "Unauthorized" }), {
      status: 401,
      headers: { "Content-Type": "application/json" },
    });
  }

  const tag = url.searchParams.get("tag"); // engineering|research|personal
  const limit = Math.min(parseInt(url.searchParams.get("limit") || "1", 10), 10);

  const db = getDb();
  const conditions = [eq(queueItem.status, "queued")];
  if (tag) conditions.push(eq(queueItem.tag, tag as any));

  const items = await db
    .select()
    .from(queueItem)
    .where(and(...conditions))
    .orderBy(asc(queueItem.createdAt))
    .limit(limit);

  return new Response(JSON.stringify({ items }), {
    headers: { "Content-Type": "application/json" },
  });
};

import type { APIRoute } from "astro";
import { getDb } from "~/lib/db";
import { queueItem, researchRun } from "~/lib/db/schema";
import { eq } from "drizzle-orm";
import { validateRunnerApiKey } from "~/lib/runner-auth";

// POST /api/queue/[id]/start — pi-runner marks item as running
export const POST: APIRoute = async ({ params, request }) => {
  const apiKey = request.headers.get("x-runner-key");
  if (!validateRunnerApiKey(apiKey)) {
    return new Response(JSON.stringify({ error: "Unauthorized" }), { status: 401 });
  }

  const { id } = params;
  if (!id) return new Response(JSON.stringify({ error: "Missing id" }), { status: 400 });

  const db = getDb();
  const now = new Date();

  await db
    .update(queueItem)
    .set({ status: "running", startedAt: now })
    .where(eq(queueItem.id, id));

  const runId = crypto.randomUUID();
  await db.insert(researchRun).values({
    id: runId,
    queueItemId: id,
    tag: (await db.select({ tag: queueItem.tag }).from(queueItem).where(eq(queueItem.id, id)))[0]?.tag || "research",
    status: "running",
    startedAt: now,
  });

  return new Response(JSON.stringify({ ok: true, runId }), {
    headers: { "Content-Type": "application/json" },
  });
};

import type { APIRoute } from "astro";
import { getDb } from "~/lib/db";
import { queueItem, researchRun } from "~/lib/db/schema";
import { eq } from "drizzle-orm";
import { validateRunnerApiKey } from "~/lib/runner-auth";

// POST /api/queue/[id]/complete — pi-runner marks item as done or failed
export const POST: APIRoute = async ({ params, request }) => {
  const apiKey = request.headers.get("x-runner-key");
  if (!validateRunnerApiKey(apiKey)) {
    return new Response(JSON.stringify({ error: "Unauthorized" }), { status: 401 });
  }

  const { id } = params;
  if (!id) return new Response(JSON.stringify({ error: "Missing id" }), { status: 400 });

  const body = await request.json().catch(() => ({}));
  const success = body.success !== false;
  const now = new Date();

  const db = getDb();

  await db
    .update(queueItem)
    .set({
      status: success ? "done" : "failed",
      completedAt: now,
      resultWikiPath: body.result_wiki_path || null,
    })
    .where(eq(queueItem.id, id));

  // Update the latest run for this item
  const runs = await db
    .select()
    .from(researchRun)
    .where(eq(researchRun.queueItemId, id))
    .orderBy(researchRun.startedAt);

  if (runs.length > 0) {
    const latestRun = runs[runs.length - 1];
    await db
      .update(researchRun)
      .set({
        status: success ? "completed" : "failed",
        completedAt: now,
        tokenCount: body.token_count || null,
        durationSeconds: body.duration_seconds || null,
        errorMessage: body.error_message || null,
        outputSummary: body.output_summary || null,
        model: body.model || null,
      })
      .where(eq(researchRun.id, latestRun.id));
  }

  return new Response(JSON.stringify({ ok: true }), {
    headers: { "Content-Type": "application/json" },
  });
};

