    return new Response("Invalid title or tag", { status: 400 });
  }

  const id = nanoid();
  const db = getDb();

  // Explicitly set timestamp as unix epoch integer for libsql compatibility
  const now = Math.floor(Date.now() / 1000);

  await db.insert(queueItem).values({
    id,
    userId: "system", // TODO: use actual user once auth is wired
    tag,
    title,
    body,
    priority,
    sourceUrl,
    status: "queued",
    createdAt: new Date(now * 1000),
  });

  return redirect("/queue");
};

import crypto from "node:crypto";

const RUNNER_API_KEYS = new Set(
  (process.env.RUNNER_API_KEYS || "").split(",").map((k) => k.trim()).filter(Boolean)
);

export function validateRunnerApiKey(key: string | null | undefined): boolean {
  if (!key) return false;
  if (RUNNER_API_KEYS.size === 0) return false; // no keys configured = no runner access
  return RUNNER_API_KEYS.has(key);
}

export function hashApiKey(key: string): string {
  return crypto.createHash("sha256").update(key).digest("hex");
}

