import Layout from "~/layouts/Layout.astro";
import { getDb } from "~/lib/db";
import { queueItem } from "~/lib/db/schema";
import { desc, asc, eq, and, sql } from "drizzle-orm";

const db = getDb();

const tag = Astro.url.searchParams.get("tag") || "all";
const statusFilter = Astro.url.searchParams.get("status") || "active";

// Build query conditions
const conditions = [];
if (tag !== "all") conditions.push(eq(queueItem.tag, tag as any));
if (statusFilter === "active") {
  conditions.push(sql`${queueItem.status} IN ('queued', 'running')`);
} else if (statusFilter !== "all") {
  conditions.push(eq(queueItem.status, statusFilter as any));
}

const items = conditions.length > 0
  ? await db.select().from(queueItem).where(and(...conditions)).orderBy(desc(queueItem.createdAt)).limit(100)
  : await db.select().from(queueItem).orderBy(desc(queueItem.createdAt)).limit(100);

// Counts by status
const counts = await db
  .select({ status: queueItem.status, count: sql<number>`count(*)` })
  .from(queueItem)
  .groupBy(queueItem.status);
const countMap = Object.fromEntries(counts.map((c) => [c.status, c.count]));

const statusColors = {
  queued: "bg-yellow-100 text-yellow-800",
  running: "bg-blue-100 text-blue-800",
  done: "bg-green-100 text-green-800",
  failed: "bg-red-100 text-red-800",
  archived: "bg-stone-100 text-stone-600",
};
