import Layout from "~/layouts/Layout.astro";
import { getDb } from "~/lib/db";
import { queueItem, researchRun } from "~/lib/db/schema";
import { eq, desc } from "drizzle-orm";

const { id } = Astro.params;
if (!id) return Astro.redirect("/queue");

const db = getDb();
const [item] = await db.select().from(queueItem).where(eq(queueItem.id, id));
if (!item) return Astro.redirect("/queue");

const runs = await db
  .select()
  .from(researchRun)
  .where(eq(researchRun.queueItemId, id))
  .orderBy(desc(researchRun.startedAt));

const statusColors = {
  queued: "bg-yellow-100 text-yellow-800",
  running: "bg-blue-100 text-blue-800",
  done: "bg-green-100 text-green-800",
  failed: "bg-red-100 text-red-800",
  archived: "bg-stone-100 text-stone-600",
};

async function handleAction(action: string) {
  if (Astro.request.method !== "POST") return null;
  const formData = await Astro.request.formData().catch(() => null);
  if (!formData) return null;
  const formAction = formData.get("action");
  if (formAction !== action) return null;
  return formData;
}

// Handle status changes
const requeueForm = await handleAction("requeue");
if (requeueForm) {
  await db.update(queueItem).set({ status: "queued", startedAt: null, completedAt: null }).where(eq(queueItem.id, id));
  return Astro.redirect(`/queue/${id}`);
}

const archiveForm = await handleAction("archive");
if (archiveForm) {
  await db.update(queueItem).set({ status: "archived" }).where(eq(queueItem.id, id));
  return Astro.redirect(`/queue/${id}`);
}

const deleteForm = await handleAction("delete");
if (deleteForm) {
  await db.delete(queueItem).where(eq(queueItem.id, id));
  return Astro.redirect("/queue");
}
