        </span>
        <span class="text-xs px-2 py-0.5 rounded-full bg-stone-100 text-stone-600">#{item.tag}</span>
        <span class="text-xs px-2 py-0.5 rounded-full bg-stone-100 text-stone-600">{item.priority}</span>
      </div>
      <h1 class="text-xl font-semibold">{item.title}</h1>
      <div class="text-sm text-stone-400 mt-1">
        Created {item.createdAt ? new Date(item.createdAt).toLocaleString() : "unknown"}
        {item.startedAt && ` · Started ${new Date(item.startedAt).toLocaleString()}`}
        {item.completedAt && ` · Completed ${new Date(item.completedAt).toLocaleString()}`}
      </div>
    </div>

    <!-- Body -->
    {item.body && (
      <div class="rounded-xl border border-stone-200 bg-white p-4">
        <h2 class="text-sm font-medium text-stone-500 mb-2">Context</h2>
        <div class="prose prose-sm max-w-none whitespace-pre-wrap">{item.body}</div>
      </div>
    )}

    <!-- Source URL -->
    {item.sourceUrl && (
      <div>
        <span class="text-sm text-stone-500">Source: </span>
        <a href={item.sourceUrl} target="_blank" rel="noopener" class="text-sm text-blue-600 hover:underline break-all">
          {item.sourceUrl}
        </a>
      </div>
    )}

    <!-- Result -->
    {item.resultWikiPath && (
      <div class="rounded-xl border border-green-200 bg-green-50 p-4">
        <h2 class="text-sm font-medium text-green-700 mb-1">Result</h2>
        <p class="text-sm text-green-600">{item.resultWikiPath}</p>
      </div>
    )}

    <!-- Actions -->
    <form method="post" class="flex gap-2 flex-wrap">
      {item.status !== "queued" && (
        <button type="submit" name="action" value="requeue"
          class="rounded-lg bg-yellow-100 text-yellow-800 px-4 py-2 text-sm font-medium hover:bg-yellow-200">
          Re-queue
        </button>
      )}
      {item.status !== "archived" && (
        <button type="submit" name="action" value="archive"
          class="rounded-lg bg-stone-100 text-stone-600 px-4 py-2 text-sm font-medium hover:bg-stone-200">
          Archive
        </button>
      )}
      <button type="submit" name="action" value="delete"
        class="rounded-lg bg-red-50 text-red-600 px-4 py-2 text-sm font-medium hover:bg-red-100"
        onclick="return confirm('Delete this item permanently?')">
        Delete
      </button>
    </form>

    <!-- Run history -->
    {runs.length > 0 && (
      <div>
        <h2 class="text-sm font-medium text-stone-500 mb-3">Run History</h2>
        <div class="space-y-2">
          {runs.map((run) => (
            <div class="rounded-lg border border-stone-200 bg-white p-3 text-sm">
              <div class="flex items-center gap-2 mb-1">
                <span class={`text-xs px-2 py-0.5 rounded-full ${
                  run.status === "completed" ? "bg-green-100 text-green-700" :
                  run.status === "running" ? "bg-blue-100 text-blue-700" :
                  "bg-red-100 text-red-700"
                }`}>{run.status}</span>
                {run.model && <span class="text-xs text-stone-400">{run.model}</span>}
              </div>
              <div class="text-stone-500">
                {run.startedAt && `Started ${new Date(run.startedAt).toLocaleString()}`}
                {run.durationSeconds && ` · ${run.durationSeconds}s`}
                {run.tokenCount && ` · ${run.tokenCount.toLocaleString()} tokens`}
              </div>
              {run.outputSummary && <p class="mt-1 text-stone-600">{run.outputSummary}</p>}
              {run.errorMessage && <p class="mt-1 text-red-600">{run.errorMessage}</p>}
            </div>
          ))}
        </div>
      </div>
    )}

    <a href="/queue" class="text-sm text-blue-600 hover:underline">← Back to queue</a>
  </div>
</Layout>
